module RefModule (
    input clk,
    input reset,
    input en,
    output reg [1:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
        q <= 2'b00;
    else if (en)
        q <= q + 1;
end
endmodule
